import requests
import base64

def build_saml_request(destination_url, user_info):
    saml_request = f'<saml><user>{user_info}</user></saml>'
    encoded_saml_request = base64.b64encode(saml_request.encode()).decode()
    response = requests.post(destination_url, data={'SAMLRequest': encoded_saml_request})
    return response.text

